<?php namespace App\Repositories\Admission;use App\Repositories\BaseRepository;use App\Models\Admission\AdmissionForm;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class AdmissionFormRepository extends BaseRepository{    public function __construct(AdmissionForm $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function findByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function searchForms(string $keyword): Collection    {        return $this->query()->where(function ($q) use ($keyword) {                $q->where('applicant_name', 'like', "%{$keyword}%")->orWhere('application_no', 'like', "%{$keyword}%")->orWhere('parent_phone', 'like', "%{$keyword}%")->orWhere('parent_email', 'like', "%{$keyword}%");            })->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('submitted_at', [$startDate, $endDate])->get();    }    public function getPendingForms(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function countByStatus(): Collection    {        return $this->query()->selectRaw('status, COUNT(*) as total')->groupBy('status')->get();    }}